import { Inference, Page } from "../../../../v1/parsing/common/index.js";
import { CarteGriseV1Document } from "./carteGriseV1Document.js";
/**
 * Carte Grise API version 1 inference prediction.
 */
export class CarteGriseV1 extends Inference {
    constructor(rawPrediction) {
        super(rawPrediction);
        /** The endpoint's name. */
        this.endpointName = "carte_grise";
        /** The endpoint's version. */
        this.endpointVersion = "1";
        /** The document's pages. */
        this.pages = [];
        this.prediction = new CarteGriseV1Document(rawPrediction["prediction"]);
        rawPrediction["pages"].forEach((page) => {
            if (page.prediction !== undefined && page.prediction !== null &&
                Object.keys(page.prediction).length > 0) {
                this.pages.push(new Page(CarteGriseV1Document, page, page["id"], page["orientation"]));
            }
        });
    }
}
